<script setup lang="ts">
import { ref,watch } from 'vue';import { ElMessage } from 'element-plus';import { useMerchantContext } from '../../stores/merchantContext';import * as m6 from './api'
const ctx=useMerchantContext();const loading=ref(false),error=ref(''),plans=ref<any[]>([]),items=ref<any[]>([]),history=ref<any[]>([]),selectedPlan=ref<any>(),selectedWork=ref<any>();
const planForm=ref<any>({diagnosisSnapshotId:'',idempotencyKey:crypto.randomUUID(),name:'30天 GEO 内容执行计划',periodStart:new Date().toISOString().slice(0,10),periodEnd:new Date(Date.now()+29*86400000).toISOString().slice(0,10),status:'DRAFT'});const workForm=ref<any>({taskType:'FAQ_CONTENT',title:'',businessValue:3,gapSeverity:3,executionFeasibility:3,evidenceConfidence:3,status:'PLANNED',targetQuestionIds:[],successCriteria:{}});const briefForm=ref<any>({status:'BRIEF_DRAFT',contentGoal:'',targetPlatform:'WEBSITE',contentType:'FAQ',targetQuestionIds:[],requiredFactIds:[],prohibitedClaims:[],contentStructure:[],successCriteria:{},retestCriteria:{}});
async function load(){if(!ctx.merchant.value)return;loading.value=true;error.value='';try{plans.value=await m6.plans(ctx.merchant.value.id)}catch(e:any){error.value=e.message}finally{loading.value=false}}async function openPlan(p:any){selectedPlan.value=p;items.value=await m6.works(ctx.merchant.value!.id,p.id);selectedWork.value=undefined;history.value=[]}async function savePlan(){try{const p=selectedPlan.value?await m6.updatePlan(ctx.merchant.value!.id,selectedPlan.value.id,planForm.value):await m6.createPlan(ctx.merchant.value!.id,planForm.value);await load();await openPlan(p);ElMessage.success('计划已保存')}catch(e:any){ElMessage.error(e.message)}}async function saveWork(){try{const x=selectedWork.value?await m6.updateWork(ctx.merchant.value!.id,selectedWork.value.id,workForm.value):await m6.createWork(ctx.merchant.value!.id,selectedPlan.value.id,workForm.value);await openPlan(selectedPlan.value);selectedWork.value=x;ElMessage.success('工作项已保存')}catch(e:any){ElMessage.error(e.message)}}async function openWork(w:any){selectedWork.value=w;history.value=await m6.briefs(ctx.merchant.value!.id,w.id)}async function saveBrief(){try{if(!selectedWork.value)return;const x=history.value.length?await m6.updateBrief(ctx.merchant.value!.id,history.value[0].id,briefForm.value):await m6.createBrief(ctx.merchant.value!.id,selectedWork.value.id,briefForm.value);history.value=await m6.briefs(ctx.merchant.value!.id,selectedWork.value.id);ElMessage.success(`Brief v${x.version} 已保存`)}catch(e:any){ElMessage.error(e.message)}}watch(()=>ctx.merchant.value?.id,load,{immediate:true})
</script>
<template><section class="module-page"><div class="module-heading"><div><span class="eyebrow">M6 · CONTENT EXECUTION</span><h2>内容执行中心</h2><p>诊断 → 30天计划 → 工作项 → 可版本化 Content Brief。</p></div></div><el-alert type="info" :closable="false" title="本阶段只管理计划和 Brief；不调用 AI、不自动发布。"/><el-alert v-if="error" type="error" :closable="false" :title="error" style="margin-top:12px"/><div class="module-columns" style="margin-top:18px"><article class="panel"><h3>执行计划</h3><el-button :loading="loading" @click="load">刷新</el-button><el-empty v-if="!plans.length&&!loading" description="暂无执行计划"/><div v-for="p in plans" :key="p.id" class="data-row"><b>{{p.name}}</b><small>{{p.period_start}} ～ {{p.period_end}} · {{p.status}}</small><el-button text @click="openPlan(p)">打开</el-button></div><h4>创建 / 编辑计划</h4><el-input v-model="planForm.diagnosisSnapshotId" placeholder="正式诊断 Snapshot ID"/><el-input v-model="planForm.name" placeholder="计划名称"/><el-date-picker v-model="planForm.periodStart" value-format="YYYY-MM-DD" type="date"/><el-date-picker v-model="planForm.periodEnd" value-format="YYYY-MM-DD" type="date"/><el-select v-model="planForm.status"><el-option v-for="x in ['DRAFT','ACTIVE','COMPLETED','CANCELLED']" :key="x" :value="x"/></el-select><el-button type="primary" @click="savePlan">保存计划</el-button></article><article class="panel"><h3>工作项与 Brief</h3><el-empty v-if="!selectedPlan" description="先打开一个计划"/><template v-else><div v-for="w in items" :key="w.id" class="data-row"><b>{{w.title}}</b><small>{{w.status}} · {{w.priority_level}} · {{w.due_date||'未设截止日期'}}</small><el-button text @click="openWork(w)">编辑 Brief</el-button></div><el-input v-model="workForm.title" placeholder="工作项标题"/><el-select v-model="workForm.status"><el-option v-for="x in ['PLANNED','IN_PROGRESS','REVIEW_PENDING','APPROVED','COMPLETED','BLOCKED','CANCELLED','SUPERSEDED']" :key="x" :value="x"/></el-select><el-button @click="saveWork">保存工作项</el-button><template v-if="selectedWork"><h4>Content Brief</h4><el-input v-model="briefForm.contentGoal" placeholder="内容目标"/><el-select v-model="briefForm.targetPlatform"><el-option value="WEBSITE"/><el-option value="ZHIHU"/><el-option value="XIAOHONGSHU"/></el-select><el-input v-model="briefForm.contentType" placeholder="内容类型"/><el-button type="primary" @click="saveBrief">创建新 Brief 版本</el-button><div v-for="b in history" :key="b.id" class="data-row"><b>v{{b.version}} · {{b.status}}</b><small>{{b.content_goal}} · {{b.target_platform}}</small></div></template></template></article></div></section></template>
